-- Seed: Customer Levels, Copy Trading Signals, and Contracts
-- Safe to run multiple times (uses INSERT IGNORE / ON DUPLICATE KEY)

-- ============================================================
-- CUSTOMER LEVELS
-- ============================================================
ON DUPLICATE KEY UPDATE name_en=VALUES(name_en), status='active';

-- ============================================================
-- TRADING SIGNALS (Copy Trading)
-- ============================================================
ON DUPLICATE KEY UPDATE status='active', updated_at=UNIX_TIMESTAMP();

-- ============================================================
-- INVEST PLANS / CONTRACTS
-- ============================================================
ON DUPLICATE KEY UPDATE status='active', updated_at=UNIX_TIMESTAMP();
